			num := nums[j]
			freq[num]++
		}
		maxFreq := int64(0)
		best := int64(-1)
		for num, cnt := range freq {
			if cnt > maxFreq {
				maxFreq = cnt
				best = num
			} else if cnt == maxFreq {
				if num < best {
					best = num
				}
			}
		}
		if maxFreq >= threshold {
			ans[i] = best
		} else {
			ans[i] = -1
		}
	}
	return ans
